INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0c700c30-moex-00608', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '在圖形理論（GraphTheory）中，有一個理論叫做尤拉循環（EulerianCycle）。該理論表示，每一個 圖（Graph）的頂點（Vertex）有邊（Edge）來連接頂點，若從其中某一個頂點出發，經過所有的邊， 然後又回到原先出發的頂點，請問需要具備什麼條件？', '["連接到每一個頂點的邊數必須是奇數", "該圖中所有的邊數總和必須可以讓頂點數總和整除", "該圖中所有的邊數總和必須是頂點數總和的偶數倍數", "連接到每一個頂點的邊數必須是偶數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00609', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '擴展樹（SpanningTree）是圖形理論（GraphTheory）中的一種運用。擴展樹是以最少的邊數來連接 圖形中所有的頂點，若圖形中的每一個邊加上一些數值當作權重（Weight），這樣的權重可以是 成本（Cost）或距離（Distance）。雖然一個圖形可能會有許多的擴張樹，但若考慮每個邊上的權重 （或成本），我們可以找到一個最小成本的擴張樹（MinimumCostSpanningTree）。以下的圖形， G=(V,E)，V是頂點，V={1,2,3,...,n}，E是連接兩個頂點的邊，邊上的數值代表權重（或成本）。 請問下圖中，關於這個圖形的最小成本擴張樹（從頂點1開始出發），下列何者正確？', '["頂點4跟頂點7的邊包含在這個最小成本擴張樹中", "最小成本擴張樹所有權重總和為50", "頂點5跟頂點7的邊包含在這個最小成本擴張樹中", "最小成本擴張樹所有權重總和為48"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00610', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '最小成本的擴張樹（MinimumCostSpanningTree）上的權重若是距離，就可以求從某一個起始節點 到終止節點的最小路徑。這可以運用到現今的物流運輸。兩個節點間的箭頭表示行進的方向。如下 圖，請問從起始節點1到終止節點7，最短的路徑，下列何者正確？', '["最短路徑距離總和19", "節點4到節點3是路徑的一部分", "節點3到節點5是路徑的一部分", "包含起始節點跟終止節點，共經過6個節點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "1e9384d08aea", "answer_pdf_sha1": "eb10e6559f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00611', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '以下何種權利屬於智慧財產權？', '["債權", "抵押權", "商標權", "姓名權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00612', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '甲基金會自創辦以來，致力於雛妓救援與家暴受害者庇護，近年尤努力消彌社會中所有性/性別暴力行為 與壓迫，以建立性別公義的社會。有關甲基金會的敘述，下列何者正確？', '["和政黨一樣都是屬於非營利組織", "從民法的屬性分類屬於社團法人", "關心社會議題的層面較政黨多元", "常藉由政治參選達成該組織宗旨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00613', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '柔柔生長在一個小康的家庭，父母親從小就栽培她學習各項才藝，塑造了柔柔高雅的氣質和談吐。上述 現象最適合用下列那一種概念加以說明？', '["經濟資本", "社會資本", "象徵資本", "文化資本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00614', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '據環保團體估計，每年約有一千多萬噸的塑膠垃圾流入海中，超過 700 種海洋物種受到海洋塑膠污染的 影響，海洋垃圾也造成對船舶航行的阻礙、生態系惡化等不良影響，前述現象最適合用下列何種概念 說明？', '["外部成本內部化", "共有財的悲歌", "搭便車心態", "鄰避效應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00615', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '某甲認為年輕人自己不夠努力因此才買不起房子，某乙反駁認為，許多財團手握大筆資金投入房地產市 場，成為炒房元兇，年輕人靠著微薄的薪水，不論如何努力也永遠追不上高漲的房價。某乙的說法最接 近下列何項觀點？', '["功能論", "衝突論", "成就地位論", "人力資本論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00616', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '美國大選常見各族群文化與價值之間的激辯，但似乎都不影響美國民眾對國家的支持。請問美國人民對 國家的齊心支持，最可能基於下列何項理由？', '["公民身分的保障形成對國家的認同", "國家透過嚴密監控形成公民意識", "透過種族通婚大幅減少社會分歧", "所得平均形成強大的社會凝聚力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00617', 'elementary-0c700c30', 'elementary-0c700c30-moex-111-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '隨著永續發展思潮的風起雲湧，消費者願意以合理價格，購買以友善耕作方式所生產的蔬果，此種購買 行為符合下列何種概念？', '["綠色廠房", "企業社會責任", "比較利益", "綠色消費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:33+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL)
